import React from "react";
import bootstrap from "bootstrap";
import "../login/style.css"

const Login = () => {
  return (
    <>
      <div className="login">
        <div className="login-child" />
        <div className="login-item" />
        <div className="login-inner" />
        <div className="rectangle-div" />
        <div className="login-child1" />
        <div className="login-child2" />
        <div className="login-child3" />
        <div className="login-child4" />
        <div className="login-child5" />
        <div className="login-child6" />
        <div className="login-child7" />
        <div className="login-child8" />
        <div className="login-child9" />
        <div className="login-child10" />
        <img className="arrow-icon" alt="" src="/arrow-1.svg" />
      </div>
    </>
  );
};
export default Login;
